from collections import OrderedDict


class OldestUniqueTracker:
    def __init__(self):
        self.count = {}            # id -> cumulative number of submits
        self.unique = OrderedDict()  # id -> True, kept in first-arrival order

    def submitItem(self, id: int) -> None:
        c = self.count.get(id, 0) + 1
        self.count[id] = c
        if c == 1:
            # first sighting -> newly unique, append to the back
            self.unique[id] = True
        elif c == 2:
            # second sighting -> now a duplicate, evict permanently
            # (it must be present since it was unique a moment ago, unless
            #  already consumed; pop with default to be safe)
            self.unique.pop(id, None)
        # c > 2 -> already not in unique, nothing to do

    def consumeOldestUnique(self) -> int:
        if not self.unique:
            return -1
        oldest_id, _ = self.unique.popitem(last=False)  # front = oldest
        return oldest_id


# ---------------- Brute force reference ----------------
class Brute:
    def __init__(self):
        self.stream = []      # (id, alive) ; consumed marked dead
        self.consumed = []    # indices consumed

    def submitItem(self, id):
        self.stream.append(id)

    def consumeOldestUnique(self):
        from collections import Counter
        freq = Counter(i for i in self.stream if i is not None)
        for idx, v in enumerate(self.stream):
            if v is not None and freq[v] == 1:
                self.stream[idx] = None  # consume/remove this occurrence
                return v
        return -1


# ---------------- Tests ----------------
def run_example(ops):
    t = OldestUniqueTracker()
    out = []
    for op in ops:
        if op[0] == 's':
            t.submitItem(op[1])
        else:
            out.append(t.consumeOldestUnique())
    return out


# Example 1
e1 = [('s',4),('s',2),('s',5),('s',1),('s',2),('c',)]
print("Ex1:", run_example(e1), "expected [4]")

# Example 2
e2 = [('s',4),('s',2),('s',5),('s',1),('s',2),('s',4),('c',)]
print("Ex2:", run_example(e2), "expected [5]")

# Edge: consume on empty
print("Empty consume:", run_example([('c',)]), "expected [-1]")

# Edge: single item
print("Single:", run_example([('s',7),('c',)]), "expected [7]")

# Edge: all duplicates -> no unique
print("All dup:", run_example([('s',9),('s',9),('c',)]), "expected [-1]")

# Edge: consume then same id resubmitted
print("Resubmit:", run_example([('s',3),('c',),('s',3),('c',)]), "expected [3, ?]")

# Randomized stress vs brute force
import random
random.seed(7)
for trial in range(2000):
    n = random.randint(1, 40)
    ops = []
    for _ in range(n):
        if random.random() < 0.65:
            ops.append(('s', random.randint(0, 6)))
        else:
            ops.append(('c',))
    fast = OldestUniqueTracker()
    slow = Brute()
    fo, so = [], []
    for op in ops:
        if op[0] == 's':
            fast.submitItem(op[1]); slow.submitItem(op[1])
        else:
            fo.append(fast.consumeOldestUnique())
            so.append(slow.consumeOldestUnique())
    if fo != so:
        print("MISMATCH", ops, fo, so)
        break
else:
    print("Stress: all 2000 random trials matched brute force")

# Large perf sanity
import time
t = OldestUniqueTracker()
start = time.time()
N = 100000
for i in range(N):
    if i % 3 == 0 and i > 0:
        t.submitItem(i % 1000)  # create duplicates
    else:
        t.submitItem(i)
cons = 0
for _ in range(N // 2):
    if t.consumeOldestUnique() != -1:
        cons += 1
print(f"Perf: {N} submits + {N//2} consumes in {time.time()-start:.3f}s, consumed={cons}")

